  (void)sb_append(&sh, "if [ -r \"$repeat_status\" ]; then nynth_repeat_status=\"$repeat_status\"; fi\n");
  (void)sb_append(&sh, "NYNTH_RUN_REPEAT=\"${NYNTH_RUN_REPEAT:-1}\"\n");
