  (void)sb_append(&sh, "NYNTH_RUN_COOLDOWN_S=\"${NYNTH_RUN_COOLDOWN_S:-0}\"\n");
  (void)sb_append(&sh, "NYNTH_RUN_HEARTBEAT_S=\"${NYNTH_RUN_HEARTBEAT_S:-300}\"\n");
  (void)sb_append(&sh, "nynth_default_stop_file=");
