  (void)sb_append(&entry, ",\"shape_hash\":");
  (void)sb_append_json_str(&entry, source_hash ? source_hash : "");
  (void)sb_append(&entry, ",\"shape_dsl_version\":1,\"template\":\"creal-function-db\","
                  "\"features\":");
